import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void classic() {
        // [[9,5,1],[8,3,2],[4]] k=4 -> [9,8,5,4]
        // max-heap pops 9(s0), 8(s1), 5(s0), 4(s2) in that order
        int[] result = new Solution().topKFromStreams(
            new int[][]{{9,5,1},{8,3,2},{4}}, 4);
        assertArrayEquals(new int[]{9, 8, 5, 4}, result);
        assertEquals(4, result.length);
    }

    @Test
    void kEqualsOne() {
        // only the single largest element across all streams
        int[] result = new Solution().topKFromStreams(
            new int[][]{{7,3},{10,1},{5}}, 1);
        assertArrayEquals(new int[]{10}, result);
    }

    @Test
    void kEqualsTotal() {
        // collect all elements; result is fully merged descending
        int[] result = new Solution().topKFromStreams(
            new int[][]{{8,5},{7,4},{6}}, 5);
        assertArrayEquals(new int[]{8, 7, 6, 5, 4}, result);
        assertEquals(5, result.length);
    }

    @Test
    void emptyStreamAmongOthers() {
        // src1 is empty — must not crash; k=3 from remaining streams
        int[] result = new Solution().topKFromStreams(
            new int[][]{{9,6,3},{},{8,5,2}}, 3);
        assertArrayEquals(new int[]{9, 8, 6}, result);
        assertEquals(3, result.length);
    }

    @Test
    void singleStream() {
        // k=1 degenerate: top-k is a prefix of the single descending stream
        int[] result = new Solution().topKFromStreams(
            new int[][]{{20, 15, 10, 5}}, 3);
        assertArrayEquals(new int[]{20, 15, 10}, result);
    }

    @Test
    void tiebreakerBySourceIndex() {
        // src0 and src1 both start with 10 (descending stream)
        // lower source index (src0) polled first -> [10,10,7]
        int[] result = new Solution().topKFromStreams(
            new int[][]{{10,3},{10,7}}, 3);
        assertArrayEquals(new int[]{10, 10, 7}, result);
        assertEquals(3, result.length);
    }

    @Test
    void manyStreamsSingleElements() {
        // each stream has one element; k=3 -> three largest in descending order
        int[] result = new Solution().topKFromStreams(
            new int[][]{{4},{8},{1},{6},{3}}, 3);
        assertArrayEquals(new int[]{8, 6, 4}, result);
    }
}
